var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"정신을 잃은 상태에서도, 어째서인지 저희를 거부하시더라고요.","JPN":"気を失った状態でも、どうしてか我々を拒否されていましたね。","ENG":"But even when you were unconscious, you were somehow refusing us.","TWN":"即使是在昏迷的狀態下，不知道為什麼，你也拒絕了我們。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"결국 제물을 전부 소진했는데도 연명 조치에 그쳤답니다.","JPN":"結果生贄を全部使っても、延命措置に留まってしまいました。","ENG":"Eventually, we were able to sustain your life after depleting all our resources.","TWN":"最後我們用光了所有祭物，也只是停在了為你勉強續命上。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니야……","JPN":"違う……","ENG":"No...","TWN":"不是的……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"고민했어요. 오직 레지나 님을 위해서.","JPN":"悩みました。レジーナ様のためだけを思って。","ENG":"We thought hard. All for your well-being, Miss Regina.","TWN":"我們苦惱了很久，為了蕾佳娜。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니야……!","JPN":"違う……！","ENG":"NO...!","TWN":"不……！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"결국 <color=#ffd34c>심연에 계신 분</color>이라면 레지나 님도 거부하지 않으리라고 판단했죠.","JPN":"結局、<color=#ffd34c>深淵にいらっしゃる方</color>なら、レジーナ様も拒否されないだろうと判断しました。","ENG":"Ultimately, we decided that even you would not be able to refuse if it is <color=#ffd34c>Him in the Gulf</color>.","TWN":"最後我們判斷，如果是<color=#ffd34c>深淵中的那位</color>，應該也不會拒絕蕾佳娜。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이번에는 특히 준비에 공을 들였어요. 그 분은 우둔한 주제에 까탈스러우셔서.","JPN":"今回は特に念入りに準備しました。あの方は鈍いくせに気難しいので。","ENG":"We worked hard to prepare for this. The Idiot is rather picky.","TWN":"這次我們特意在準備方面下了功夫。因為那位存在雖然有些盲目，但同時又很挑剔。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"질문에 답해 드릴게요. 합중국을 공격한 건 제 지시가 맞아요.","JPN":"質問にお答えしましょう。合衆国を攻撃したのは確かに我々が指示したことです。","ENG":"We'll answer your question. Yes, we ordered the attack on the States.","TWN":"我們來回答你的問題。攻擊合眾國是我們的指示沒錯。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"물론 혹시 나타날지 모를 방해꾼들의 이목을 잠시 돌려 두기 위해서랍니다.","JPN":"もちろん、現れるかもしれない邪魔者の目をしばらく逸らせるためです。","ENG":"However, it was to divert the attention of any intruders who might appear here.","TWN":"當然是為了暫時轉移可能會出來礙事之人的注意力。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"전쟁을 할 의도는 아니었어요. 그랬다면 다른 저희를 보내지도 않았겠죠.","JPN":"戦争を起こすつもりはありませんでした。あったなら、別の我々を向かわせることもなかったでしょう。","ENG":"We did not want war. If we did, we wouldn't have sent another \\"us\\".","TWN":"我們的意圖不是發動戰爭。如果是那樣，我們就不會派出其他分身了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님, 듣고 계신가요?","JPN":"レジーナ様、聞いていますか？","ENG":"Miss Regina, are you listening?","TWN":"蕾佳娜，你在聽嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"최대한 쉽게 풀어 말씀드렸다고 생각했는데, 아직 부족한가 보네요.","JPN":"できるだけわかりやすく説明したつもりでしたが、まだ足りないようですね。","ENG":"We're doing everything we can to make it as simple as possible. But perhaps it isn't simple enough.","TWN":"我們覺得已經盡可能簡單地為你解釋了，但是好像還不夠。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"아직 어린 나이요. 전부 자기 때문에 벌어진 일이란 사실을 받아들이기 힘들겠지.","JPN":"まだ幼い。すべてが自分のせいで起こったという事実が受け入れがたいのだろう。","ENG":"She's still young. It'll be hard for her to accept the fact that this all happened because of her.","TWN":"她年紀還小。應該很難接受一切都是因自己而起，這種現實吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"의식은 어떻소?","JPN":"儀式はどうだ？","ENG":"How is the ritual going?","TWN":"儀式怎麼樣了？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"순조롭습니다. 이대로라면 무척이나 값진 결과를 얻을 수 있겠어요.","JPN":"順調です。このままいくと、大変貴重な結果を得ることができるでしょう。","ENG":"It is going smoothly. At this rate, we will obtain an extremely valuable outcome.","TWN":"很順利。照這樣下去，應該能得到非常有價值的成果。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"균열의 규모도 충분하군요. 의식은 곧 완성될 것입니다.","JPN":"亀裂の規模も十分です。もうすぐ儀式が完成されます。","ENG":"The scale of the dimensional rift is sufficient. The ritual will soon be complete.","TWN":"裂縫的規模也夠了。儀式就要完成了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"축하드리오, 학회장. 잠시 후에 공들인 성과를 확인할 수 있겠군.","JPN":"おめでとう、学会長。しばらくしたら念を入れた成果を確認することができるだろう。","ENG":"Congratulations, President. We will soon enjoy the results of our efforts.","TWN":"恭喜你，學會長。稍後就能確認你嘔心瀝血的成果了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하이드리히 소장도 충분히 수고해 주셨어요.","JPN":"ハイドリヒ所長も十分頑張ってくださいました。","ENG":"As to you, Chief Heydrich. You did well.","TWN":"海德里希所長，你也辛苦了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};